export function TableModelParser(data) {
    this.data = data;
    this.cache = {
        columns: {}
    };
}

let proto = TableModelParser.prototype;

proto.getRowCount = function() {};

proto.getColumnCount = function(seriesIdx) {};

proto.getKeys = function(columnIdx) {
    let _cached = this.cache.columns[columnIdx];
    if (_cached && _cached.keys) {
        return _cached.keys;
    }
    let _map = this.getRowData(columnIdx);
    return _map.keys;
};

proto.getRowData = function(columnIdx) {
    let _cached = this.cache.columns[columnIdx];
    if (_cached && _cached.values) {
        return _cached.values;
    }
    // _cached = {};
    let _map = this.groupData(columnIdx),
        keys = new Array(0),
        values = new Array(0);
    _map.forEach((value, key) => {
        keys.push(key);
        values.push(value);
    });
    _cached.keys = keys;
    _cached.values = values;
    return _cached.values;
};

proto.getRowDataByKey = function(columnIdx, key) {
    let _map = this.groupData(columnIdx);
    return _map.get(key);
};

proto.groupData = function(columnIdx) {
    let _cached = this.cache.columns[columnIdx];
    if (_cached) {
        return _cached.group;
    }
    _cached = {};
    let _map = (_cached.group = d3.group(this.data, d => d[columnIdx]));
    return _map;
};
